/* ============================================================================
   CIVICTRACK APP ENGINE
   Vanilla JS, hash-based router, no backend. Session state lives in
   sessionStorage only (cleared when the browser tab closes) — appropriate
   for a demo, not a real auth system.

   Session shape: { role, since, geoId, constituencyId, subCountyId, wardId,
   cellId } — geoId is always one of the canonical ids in CT_DATA.geo; the
   deeper picks are the same id scheme (see data.js).
   ========================================================================= */

// ---------------------------------------------------------------------------
// SESSION
// ---------------------------------------------------------------------------
const CT_ROLES = {
  mp:  { label: "Member of Parliament", badge: "Tier 1", badgeClass: "badge-tier1", home: "#/mp/dashboard" },
  lc5: { label: "LC5 — District Council", badge: "LC5", badgeClass: "badge-lc5", home: "#/lc5/dashboard" },
  lc3: { label: "LC3 — Sub-county Council", badge: "LC3", badgeClass: "badge-lc3", home: "#/lc3/dashboard" },
  lc2: { label: "LC2 — Parish Council", badge: "LC2", badgeClass: "badge-lc2", home: "#/lc2/dashboard" },
  lc1: { label: "LC1 — Village Council", badge: "LC1", badgeClass: "badge-lc1", home: "#/lc1/dashboard" }
};

function ctGetSession(){
  try { return JSON.parse(sessionStorage.getItem('ct_session') || 'null'); } catch(e){ return null; }
}
// Called when the demo sign-in completes. This demo accepts ANY credentials,
// including a blank submission — there is no real validation. The session at
// this point is "authenticated but no account picked yet"; the router sends
// the user to #/accounts to choose a demo account (MP or LC).
function ctCreateSession(){
  sessionStorage.setItem('ct_session', JSON.stringify({ authenticated: true, since: Date.now() }));
}
function ctUpdateSession(patch){
  const s = ctGetSession() || {};
  Object.assign(s, patch);
  sessionStorage.setItem('ct_session', JSON.stringify(s));
}
// Records the chosen demo account (role + full geography picks) into the
// session and sends the user to that role's dashboard.
// persona: { role, geoId, constituencyId?, subCountyId?, wardId?, cellId?, label? }
function ctLoginAsPersona(persona){
  ctUpdateSession({
    role: persona.role,
    geoId: persona.geoId || null,
    constituencyId: persona.constituencyId || null,
    subCountyId: persona.subCountyId || null,
    wardId: persona.wardId || null,
    cellId: persona.cellId || null
  });
  ctToast('Signed in as ' + (persona.label || CT_ROLES[persona.role].label) + ' (demo account)');
  location.hash = CT_ROLES[persona.role].home;
}
// Logout fully clears session state — so a fresh login always starts back at
// the sign-in screen with nothing remembered.
function ctLogout(){
  sessionStorage.removeItem('ct_session');
  sessionStorage.removeItem('ct_pending_role');
  location.hash = '#/login';
}

// ---------------------------------------------------------------------------
// BRAND LOGOS — shown together on EVERY screen (brief: both logos present on
// every page; bigger on the home/sign-in pages, smaller on inner pages).
// CT_NICE_UG_LOGO is the real NICE-UG logo (crested crane + wordmark),
// embedded as a data URI so the delivered files stay fully self-contained.
// CT_COMPASS_LOGO is the CivicTrack mark: a compass rose in the Ugandan
// flag colours (black dial, yellow needle star, red intercardinal star).
// ---------------------------------------------------------------------------
const CT_NICE_UG_LOGO = 'data:image/png;base64,';

const CT_COMPASS_LOGO = 'data:image/svg+xml;utf8,' + encodeURIComponent(
  '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><circle cx="32" cy="32" r="30" fill="#1A1A1A"/><circle cx="32" cy="32" r="25" fill="none" stroke="#FCDC04" stroke-width="2.4"/><g stroke="#FCDC04" stroke-width="2.2" stroke-linecap="round"><line x1="32" y1="4" x2="32" y2="8.5"/><line x1="32" y1="55.5" x2="32" y2="60"/><line x1="4" y1="32" x2="8.5" y2="32"/><line x1="55.5" y1="32" x2="60" y2="32"/></g><path d="M32 16.5 L35 29 L47.5 32 L35 35 L32 47.5 L29 35 L16.5 32 L29 29 Z" fill="#D21034" transform="rotate(45 32 32)"/><path d="M32 11 L35.5 28.5 L53 32 L35.5 35.5 L32 53 L28.5 35.5 L11 32 L28.5 28.5 Z" fill="#FCDC04"/><circle cx="32" cy="32" r="4.6" fill="#1A1A1A" stroke="#FFFFFF" stroke-width="2"/></svg>'
);

// Brand lockup: CivicTrack compass + NICE-UG side by side.
// size: 'lg' (home / sign-in pages) or 'sm' (topbar on every inner page).
function ctBrandLogos(size){
  const cls = size === 'lg' ? 'brand-lg' : 'brand-sm';
  return '<span class="brand-row ' + cls + '">' +
    '<img src="' + CT_COMPASS_LOGO + '" alt="CivicTrack" class="brand-compass">' +
    '<img src="' + CT_NICE_UG_LOGO + '" alt="NICE-UG — National Initiative for Civic Education in Uganda" class="brand-nice">' +
    '</span>';
}

// ---------------------------------------------------------------------------
// TOAST — "Demo Mode" confirmations for every simulated submission
// ---------------------------------------------------------------------------
function ctToast(message, opts){
  opts = opts || {};
  let stack = document.querySelector('.toast-stack');
  if (!stack){ stack = document.createElement('div'); stack.className = 'toast-stack'; document.body.appendChild(stack); }
  const el = document.createElement('div');
  el.className = 'toast';
  el.innerHTML = '<span class="dot"></span><span>' + message + '</span>';
  stack.appendChild(el);
  setTimeout(() => {
    el.classList.add('leaving');
    setTimeout(() => el.remove(), 250);
  }, opts.duration || 3200);
}
function ctDemoModeToast(action){
  ctToast((action ? action + ' — ' : '') + 'Demo Mode — displayed for demonstration only, not permanently stored.', { duration: 3800 });
}

// ---------------------------------------------------------------------------
// MODAL — two flavors: real content (ctInfoModal) and a DEMO stamp for
// tiles/rows that don't have verified data behind them yet (ctDemoModal).
// Every clickable dashboard element resolves to one of these two — nothing
// is a dead click.
// ---------------------------------------------------------------------------
function ctOpenModal(innerHtml, opts){
  opts = opts || {};
  ctCloseModal();
  const overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.id = 'ctModalOverlay';
  overlay.onclick = function(e){ if (e.target === overlay) ctCloseModal(); };
  overlay.innerHTML = '<div class="modal-box' + (opts.wide ? ' modal-wide' : '') + '" style="position:relative;">' +
    '<button class="modal-close" onclick="ctCloseModal()" aria-label="Close">✕</button>' + innerHtml + '</div>';
  document.body.appendChild(overlay);
  document.addEventListener('keydown', ctModalEscHandler);
}
function ctCloseModal(){
  const el = document.getElementById('ctModalOverlay');
  if (el) el.remove();
  document.removeEventListener('keydown', ctModalEscHandler);
}
function ctModalEscHandler(e){ if (e.key === 'Escape') ctCloseModal(); }

function ctInfoModal(title, bodyHtml, sourceLine){
  ctOpenModal(`
    <h3>${title}</h3>
    <div style="margin-top:10px;">${bodyHtml}</div>
    ${sourceLine ? `<div class="footer-note" style="margin-top:16px;text-align:left;font-style:normal;">${sourceLine}</div>` : ''}
  `);
}

function ctDemoModal(title, note){
  ctOpenModal(`
    <div class="demo-stamp-wrap">
      <div class="demo-stamp">DEMO</div>
      <h3 style="margin-top:6px;">${title}</h3>
      <p style="font-size:13px;color:var(--ct-text-secondary);line-height:var(--lh-sm);margin-top:6px;">
        ${note || 'This element is not backed by a verified figure from a reviewed government report in this prototype. In the production version, this would open a live drill-down connected to the underlying data source.'}
      </p>
    </div>`);
}

// DEMO watermark overlay — for whole views or panels that have no verified
// underlying data. The screen still opens and renders normally; the watermark
// makes the placeholder status unmistakable (brief requirement 3).
function ctDemoWatermark(note){
  return `<div class="demo-watermark-overlay" aria-hidden="true"><span class="demo-watermark-text">DEMO</span></div>` +
    (note ? `<div class="demo-watermark-note">${note}</div>` : '');
}

// Small availability chip used by the four-dimension views.
function ctDimChip(available){
  return available
    ? '<span class="dim-chip verified">✓ verified data</span>'
    : '<span class="dim-chip demo">DEMO — no data</span>';
}

// Photo capture (real local preview — the image never leaves the device in
// this demo; the submission confirmation is a Demo Mode toast).
function ctPhotoPreview(input){
  if (!input.files || !input.files[0]) return; // user cancelled the picker
  const reader = new FileReader();
  reader.onload = function(e){
    const box = input.closest('.photo-box');
    if (box){
      box.classList.add('has-photo');
      box.innerHTML = '<img class="photo-preview" src="' + e.target.result + '" alt="captured site photo">' +
        '<span class="photo-retake">✓ Photo attached — tap to retake</span>';
      box.appendChild(input);
    }
  };
  reader.readAsDataURL(input.files[0]);
}

// ---------------------------------------------------------------------------
// THEME TOGGLE
// ---------------------------------------------------------------------------
function ctToggleTheme(){
  const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
  document.documentElement.setAttribute('data-theme', isDark ? 'light' : 'dark');
  localStorage.setItem('ct_theme', isDark ? 'light' : 'dark');
}
(function ctInitTheme(){
  const saved = localStorage.getItem('ct_theme');
  if (saved === 'dark') document.documentElement.setAttribute('data-theme', 'dark');
})();

// ---------------------------------------------------------------------------
// COMPONENT BUILDERS — small functions returning HTML strings, reused by
// every view so the same KPI card, status pill, etc. looks identical everywhere.
// ---------------------------------------------------------------------------
function ctBreadcrumb(items){
  return '<div class="breadcrumb">' + items.map((it, i) => {
    const sep = i > 0 ? '<span class="sep">/</span>' : '';
    return sep + (it.href ? `<a href="${it.href}">${it.label}</a>` : `<span class="current">${it.label}</span>`);
  }).join('') + '</div>';
}

function ctStatusPill(status, label){
  const map = { stalled: 'stalled', pending: 'pending', ontrack: 'ontrack', complete: 'complete' };
  const cls = map[status] || 'pending';
  const text = label || { stalled: 'Stalled', pending: 'Pending', ontrack: 'On track', complete: 'Complete' }[status];
  return `<span class="status-pill ${cls}">${text}</span>`;
}

function ctProjectRow(p, linkBase){
  const href = linkBase ? `${linkBase}${p.id}` : '#';
  return `
    <a href="${href}" style="text-decoration:none;color:inherit;display:block;">
      <div class="row">
        <div><div class="row-title">${p.name}</div><div class="row-sub">${p.sector || ''}${p.location ? ' · ' + p.location : ''}</div></div>
        ${ctStatusPill(p.stageStatus)}
      </div>
    </a>`;
}

function ctProgrammeTile(prog, opts){
  opts = opts || {};
  const displayPct = prog.pctOfRevised != null ? prog.pctOfRevised : prog.pct;
  const statusClass = displayPct == null ? '' : (displayPct >= (opts.paceTarget || 50) ? 'good' : (displayPct < 20 ? 'danger' : 'amber'));
  const hasExpand = !!(prog.subLines || prog.note);
  const uid = 'exp_' + prog.name.replace(/[^a-z0-9]/gi, '').slice(0, 24) + '_' + (opts.uidSuffix || '');
  let sub = '';
  if (hasExpand){
    sub = `<div class="expand-panel" id="${uid}"><div class="expand-panel-inner">`;
    if (prog.note){
      sub += `<p style="font-size:11px;color:var(--ct-text-muted);margin-bottom:8px;">${prog.note}</p>`;
    }
    (prog.subLines || []).forEach(sl => {
      if (sl.notAvailable){
        sub += `<div class="expand-subrow"><span class="sublabel">${sl.label}</span><span class="subvalue" style="color:var(--ct-text-muted);font-weight:500;font-size:11px;">${sl.note}</span></div>`;
      } else {
        sub += `<div class="expand-subrow"><span class="sublabel">${sl.label}</span><span class="subvalue amber">${sl.pct}% of ${ctFormatUGX(sl.approved)}</span></div>`;
      }
    });
    sub += `</div></div>`;
  }
  const clickAttr = opts.onClick ? ` onclick="${opts.onClick}"` : '';
  const clickable = opts.onClick ? ' clickable' : (opts.clickable ? ' clickable' : '');
  const cta = opts.onClick ? '<div class="cta">Programme breakdown →</div>' : '';
  return `
    <div class="indicator-card${clickable}"${clickAttr}>
      <div class="icat${hasExpand ? ' expand-trigger' : ''}" ${hasExpand ? `onclick="event.stopPropagation();this.classList.toggle('open');document.getElementById('${uid}').classList.toggle('open')"` : ''}>
        ${prog.name}${hasExpand ? ' <span class="expand-icon">▸</span>' : ''}
      </div>
      <div class="ival ${statusClass}">${displayPct != null ? displayPct + '%' : ctFormatUGX(prog.approved)}</div>
      <div class="isub">of ${ctFormatUGX(prog.revisedApproved || prog.approved)} released</div>
      ${sub}${cta}
    </div>`;
}

// Topbar with browser-style back/forward, NICE-UG chip, role badge and the
// current session geography (clickable — re-opens the geography picker).
function ctTopbar(title, sub, roleKey){
  const role = CT_ROLES[roleKey];
  const s = ctGetSession() || {};
  const initials = (s.label || role.label).split(/\s+/).filter(w => /^[A-Z]/.test(w)).map(w => w[0]).slice(0, 2).join('');
  const top = `
    <div class="topbar">
      <button class="theme-toggle nav-arrow-btn" onclick="history.back()" style="position:static;" title="Back">‹</button>
      ${ctBrandLogos('sm')}
      <div style="flex:1;min-width:0;">
        <div class="topbar-title">${title}</div>
        <div class="topbar-sub">${sub}</div>
      </div>
      <button class="avatar-btn" onclick="ctOpenAccountSheet()" title="Account">
        <span class="avatar-initials">${initials}</span>
        <span class="badge ${role.badgeClass} avatar-badge">${role.badge}</span>
      </button>
    </div>`;
  return top + ctBottomNav(roleKey) + ctFAB(roleKey) + ctAccountSheet(roleKey);
}

// ---------------------------------------------------------------------------
// BOTTOM TAB BAR — persistent on all authenticated screens (login/accounts
// never call ctTopbar, so they stay clean). 5 destinations; the middle slot
// is role-specific (Projects for MP/LC5, Mobilize for LC3/LC2/LC1).
// ---------------------------------------------------------------------------
function ctBottomNav(roleKey){
  const h = (location.hash || '').split('?')[0];
  const tabs = [
    { icon: '🏠', label: 'Home', href: CT_ROLES[roleKey].home, match: CT_ROLES[roleKey].home },
    { icon: '📁', label: 'Projects', href: '#/projects', match: '#/projects' },
    { icon: '💬', label: 'Coordination', href: '#/coordination', match: '#/coordination' },
    { icon: '👥', label: 'Network', href: '#/directory', match: '#/directory' },
    { icon: '☰', label: 'More', action: 'ctOpenAccountSheet()', match: null }
  ];
  return `<nav class="tabbar">
    ${tabs.map(t => {
      const active = t.match && h.startsWith(t.match);
      const inner = `<span class="tab-icon">${t.icon}</span><span class="tab-label">${t.label}</span>`;
      return t.action
        ? `<button class="tab-item" onclick="${t.action}">${inner}</button>`
        : `<a class="tab-item${active ? ' active' : ''}" href="${t.href}">${inner}</a>`;
    }).join('')}
  </nav>`;
}

// ---------------------------------------------------------------------------
// FAB — jumps into the act-on-it flow: opens the compass action sheet, which
// leads with the top data-driven recommendation and offers Collect/Mobilize.
// ---------------------------------------------------------------------------
function ctFAB(roleKey){
  return `<button class="fab" onclick="ctCompassSheet('${roleKey}')" title="Recommended next actions">🧭</button>`;
}

// ---------------------------------------------------------------------------
// ACCOUNT SHEET — slide-out from the avatar: identity, switch demo account,
// theme toggle, logout. Keeps the topbar slim.
// ---------------------------------------------------------------------------
function ctAccountSheet(roleKey){
  const s = ctGetSession() || {};
  const role = CT_ROLES[roleKey];
  const area = s.geoId ? ctGeoName(s.constituencyId || s.subCountyId || s.wardId || s.cellId || s.geoId) : '';
  return `
    <div class="sheet-overlay" id="ctAccountSheet" onclick="if(event.target===this)ctCloseAccountSheet()">
      <div class="acct-sheet">
        <div class="acct-sheet-grab"></div>
        <div class="acct-id">
          <div class="acct-id-avatar">${(s.label || role.label).split(/\s+/).filter(w => /^[A-Z]/.test(w)).map(w => w[0]).slice(0, 2).join('')}</div>
          <div>
            <div class="row-title">${s.label || role.label}</div>
            <div class="row-sub">${role.label}${area ? ' · ' + area : ''} · demo session</div>
          </div>
        </div>
        <div class="row" style="cursor:pointer;" onclick="ctCloseAccountSheet();location.hash='#/profile'">
          <div class="row-title">🪪 My leadership profile</div><span class="chevron">›</span></div>
        <div class="row" style="cursor:pointer;" onclick="ctCloseAccountSheet();location.hash='#/knowledge'">
          <div class="row-title">📚 Knowledge Centre</div><span class="chevron">›</span></div>
        <div class="row" style="cursor:pointer;" onclick="ctCloseAccountSheet();location.hash='#/directory'">
          <div class="row-title">👥 Leadership network</div><span class="chevron">›</span></div>
        <div class="row" style="cursor:pointer;" onclick="ctCloseAccountSheet();location.hash='#/accounts'">
          <div class="row-title">🔄 Switch demo account</div><span class="chevron">›</span></div>
        <div class="row" style="cursor:pointer;" onclick="ctToggleTheme()">
          <div class="row-title">🌓 Toggle dark / light mode</div><span class="chevron">›</span></div>
        <div class="row" style="cursor:pointer;" onclick="ctLogout()">
          <div class="row-title" style="color:var(--ct-red);">⎋ Log out</div><span class="chevron">›</span></div>
        <div class="footer-note" style="margin-top:10px;">Demo Mode — sessions are simulated; no real credentials or messages exist.</div>
      </div>
    </div>`;
}
function ctOpenAccountSheet(){
  const el = document.getElementById('ctAccountSheet');
  if (el) el.classList.add('open');
}
function ctCloseAccountSheet(){
  const el = document.getElementById('ctAccountSheet');
  if (el) el.classList.remove('open');
}

function ctDrillTabs(tabs, activeIndex){
  return '<div class="drill-tabs">' + tabs.map((t, i) =>
    `<button class="drill-tab${i === (activeIndex||0) ? ' active' : ''}" onclick="ctSwitchDrillTab(this,'${t.id}')">${t.label}</button>`
  ).join('') + '</div>';
}
function ctSwitchDrillTab(btn, panelId){
  const container = btn.closest('.drill-tabs').parentElement;
  container.querySelectorAll('.drill-tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  container.querySelectorAll('.drill-panel').forEach(p => p.classList.remove('active'));
  container.querySelector(`[data-panel="${panelId}"]`).classList.add('active');
}

function ctConstitutionalNote(text){
  return `<div class="constitutional-note"><span class="icon">ⓘ</span><span><strong>Role reminder:</strong> ${text}</span></div>`;
}

function ctPrevNextNav(list, currentId, hrefBase){
  const idx = list.findIndex(p => p.id === currentId);
  if (idx === -1) return '';
  const prev = idx > 0 ? list[idx - 1] : null;
  const next = idx < list.length - 1 ? list[idx + 1] : null;
  return `
    <div class="proj-nav">
      ${prev
        ? `<a class="proj-nav-btn" href="${hrefBase}${prev.id}"><span class="proj-nav-arrow">‹</span><span><span class="proj-nav-label">Previous</span><span class="proj-nav-name">${prev.name}</span></span></a>`
        : `<span class="proj-nav-btn disabled"><span class="proj-nav-arrow">‹</span><span><span class="proj-nav-label">Previous</span><span class="proj-nav-name">Start of list</span></span></span>`}
      <span class="proj-nav-pos">${idx + 1} / ${list.length}</span>
      ${next
        ? `<a class="proj-nav-btn next" href="${hrefBase}${next.id}"><span><span class="proj-nav-label">Next</span><span class="proj-nav-name">${next.name}</span></span><span class="proj-nav-arrow">›</span></a>`
        : `<span class="proj-nav-btn disabled next"><span><span class="proj-nav-label">Next</span><span class="proj-nav-name">End of list</span></span><span class="proj-nav-arrow">›</span></span>`}
    </div>`;
}

// ---------------------------------------------------------------------------
// ROUTER — exact paths plus :param patterns (e.g. #/place/:geoId).
// ---------------------------------------------------------------------------
const CT_ROUTES = {};
const CT_ROUTE_PATTERNS = [];
function ctRoute(path, fn){
  if (path.indexOf(':') !== -1){
    const parts = path.split('/');
    CT_ROUTE_PATTERNS.push({ parts: parts, fn: fn });
  } else {
    CT_ROUTES[path] = fn;
  }
}
// Returns { fn, params } for a hash path (query string already stripped), or null.
function ctMatchRoute(path){
  if (CT_ROUTES[path]) return { fn: CT_ROUTES[path], params: {} };
  const segs = path.split('/');
  for (const pat of CT_ROUTE_PATTERNS){
    if (pat.parts.length !== segs.length) continue;
    const params = {};
    let ok = true;
    for (let i = 0; i < pat.parts.length; i++){
      const pp = pat.parts[i];
      if (pp.charAt(0) === ':'){ params[pp.slice(1)] = decodeURIComponent(segs[i]); }
      else if (pp !== segs[i]){ ok = false; break; }
    }
    if (ok) return { fn: pat.fn, params: params };
  }
  return null;
}

function ctGetQuery(){
  const h = location.hash;
  const q = h.indexOf('?');
  const out = {};
  if (q !== -1){
    h.slice(q + 1).split('&').forEach(kv => {
      const pair = kv.split('=');
      if (pair[0]) out[decodeURIComponent(pair[0])] = decodeURIComponent(pair[1] || '');
    });
  }
  return out;
}

function ctRender(){
  const app = document.getElementById('app');
  const session = ctGetSession();
  let path = (location.hash || '#/login').split('?')[0];

  const publicRoutes = ['#/login'];
  if (!publicRoutes.includes(path) && !session){
    location.hash = '#/login';
    return;
  }
  // Signed in but no demo account picked yet → the account picker is
  // mandatory before any role screen (it is what scopes the session's data).
  if (session && (!session.role || !session.geoId) && path !== '#/accounts'){
    location.hash = '#/accounts';
    return;
  }
  const roleInPath = Object.keys(CT_ROLES).find(r => path.startsWith('#/' + r + '/'));
  if (roleInPath && session && session.role && roleInPath !== session.role){
    if (!path.includes('/project')) { location.hash = CT_ROLES[session.role].home; return; }
  }

  const fallback = session && session.role ? CT_ROLES[session.role].home : (session ? '#/accounts' : '#/login');
  const match = ctMatchRoute(path) || ctMatchRoute(fallback);
  app.innerHTML = match.fn(session, match.params);
  window.scrollTo(0, 0);
}
window.addEventListener('hashchange', ctRender);
window.addEventListener('DOMContentLoaded', () => { if (!location.hash) location.hash = '#/login'; ctRender(); });

// ---------------------------------------------------------------------------
// EXECUTIVE CHARTS — dependency-free inline SVG. Every chart answers a
// decision question; nothing decorative.
// ---------------------------------------------------------------------------
// Progress ring: one number that matters, at a glance.
function ctRing(pct, opts){
  opts = opts || {};
  const size = opts.size || 84, stroke = opts.stroke || 9;
  const color = opts.color || 'var(--ct-yellow)';
  const track = opts.track || 'var(--ct-border)';
  const r = (size - stroke) / 2, c = 2 * Math.PI * r;
  const off = c * (1 - Math.max(0, Math.min(100, pct)) / 100);
  return `<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}" class="ct-ring">
    <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="${track}" stroke-width="${stroke}"/>
    <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="${color}" stroke-width="${stroke}"
      stroke-linecap="round" stroke-dasharray="${c}" stroke-dashoffset="${off}"
      transform="rotate(-90 ${size/2} ${size/2})" style="transition:stroke-dashoffset 0.8s var(--ease-out);"/>
    <text x="50%" y="47%" text-anchor="middle" dominant-baseline="middle" class="ct-ring-val">${pct}%</text>
    <text x="50%" y="64%" text-anchor="middle" dominant-baseline="middle" class="ct-ring-label">${opts.label || ''}</text>
  </svg>`;
}
// Donut: composition of a whole (e.g. programmes on pace vs behind).
function ctDonut(segments, opts){
  opts = opts || {};
  const size = opts.size || 92, stroke = opts.stroke || 13;
  const r = (size - stroke) / 2, c = 2 * Math.PI * r;
  let acc = 0;
  const arcs = segments.map(s => {
    const len = c * s.pct / 100;
    const el = `<circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="${s.color}" stroke-width="${stroke}"
      stroke-dasharray="${len} ${c - len}" stroke-dashoffset="${-c * acc / 100}"
      transform="rotate(-90 ${size/2} ${size/2})"/>`;
    acc += s.pct;
    return el;
  }).join('');
  return `<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">
    <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="var(--ct-border)" stroke-width="${stroke}"/>
    ${arcs}
    <text x="50%" y="47%" text-anchor="middle" dominant-baseline="middle" class="ct-ring-val">${opts.center || ''}</text>
    <text x="50%" y="64%" text-anchor="middle" dominant-baseline="middle" class="ct-ring-label">${opts.label || ''}</text>
  </svg>`;
}
// Sparkline: trend without axes clutter.
function ctSpark(values, opts){
  opts = opts || {};
  const w = opts.w || 96, h = opts.h || 30, color = opts.color || 'var(--ct-green)';
  const min = Math.min.apply(null, values), max = Math.max.apply(null, values);
  const span = (max - min) || 1;
  const pts = values.map((v, i) => (i * w / (values.length - 1)).toFixed(1) + ',' + (h - 3 - (v - min) * (h - 6) / span).toFixed(1)).join(' ');
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">
    <polyline points="${pts}" fill="none" stroke="${color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    <circle cx="${w}" cy="${(h - 3 - (values[values.length-1] - min) * (h - 6) / span).toFixed(1)}" r="2.6" fill="${color}"/>
  </svg>`;
}
